// Handle Password fields

// add password visibility toggle
$(document).on('click', '[data-toggle="password"]', function() {
  let $icon = $(this).find('i');

  let $password = $($(this).attr('data-target'));
  // Check if the password field exists using the 'data-target' attribute.
  // If it doesn't exist, fallback to finding the closest '.form-group' parent
  // and locate the 'input' field within it. This ensures compatibility with
  // forms where the 'data-target' attribute is not explicitly defined.
  if ($password.length === 0) {
    $password = $(this).closest('.form-group').find('input');
  }

  if ($icon.length > 0 && $password.length > 0) {
    if ($password.attr('type') == 'password') {
      $password.attr('type', 'text')
      $icon.removeClass('fa-eye').addClass('fa-eye-slash');
    } else {
      $password.attr('type', 'password');
      $icon.removeClass('fa-eye-slash').addClass('fa-eye');
    }
    $password.focus();
  }
});

// hide toggled password when form is submitted
$(document).on('submit', 'form', function() {
  let $passwords = $(this).find('[data-toggle="password"]');
  $.each($passwords, function() {
    let $icon = $(this).find('i');
    let $password = $($(this).attr('data-target'));
    if ($icon.length > 0 && $password.length > 0) {
      $password.attr('type', 'password');
      $icon.removeClass('fa-eye-slash').addClass('fa-eye');
    }
  });

});
(()=> {

    // Handle touch swipe (left or right)
    const _originalHandleSwipe = bootstrap.Carousel.prototype._handleSwipe;
    bootstrap.Carousel.prototype._handleSwipe = function _handleSwipe() {
        if ($(this._element).css('direction') === 'rtl') this.touchDeltaX = this.touchDeltaX * -1;
        _originalHandleSwipe.apply(this);
    };

    // Handle keyboard press (left or right)
    const _originalKeydown = bootstrap.Carousel.prototype._keydown;
    const ARROW_LEFT_KEYCODE = 37; // KeyboardEvent.which value for left arrow key
    const ARROW_RIGHT_KEYCODE = 39; // KeyboardEvent.which value for right arrow key
    bootstrap.Carousel.prototype._keydown = function _keydown(event) {
        if ($(event.target).css('direction') === 'rtl') {
            if (/input|textarea/i.test(event.target.tagName)) {
                return;
            }
            switch (event.which) {
                case ARROW_LEFT_KEYCODE:
                    event.preventDefault();
                    this.next();
                    break;

                case ARROW_RIGHT_KEYCODE:
                    event.preventDefault();
                    this.prev();
                    break;
            }
        } else _originalKeydown.apply(this, [event]);
    };

})();
