// make fixed body when modal/sidebar is open feel like it keeps the page scroll even though it's in a fixed position
$(document).on('freeze', 'body', function(e, freezeOnly) {
  let frozenBodyMarginTop = document.documentElement.style.getPropertyValue('--frozen-body-mt');
  if (frozenBodyMarginTop == '') { // only if body isn't frozen already


    let rect = document.body.getBoundingClientRect(); // check if scrollbar is present
    if (rect.left + rect.right < window.innerWidth) $('html').addClass('overflow-y-scroll'); // when body is frozen and a scrollbar is present we add overflow-y-scroll to html to preserve the scroll bar

    let pageScroll = $(window).scrollTop();
    document.documentElement.style.setProperty('--frozen-body-mt',`${pageScroll*-1}px`);
    $('body, html').addClass(freezeOnly ? freezeOnly : 'freeze');
    $('body').trigger('frozen');

    // when body is frozen scroll restoration should be manual
    history.scrollRestoration = 'manual';
  }
});

// restore page scroll after changing body from fixed to it's original position
$(document).on('unfreeze', 'body', function(e, unfreezeOnly) {
  let pageScroll = parseInt(document.documentElement.style.getPropertyValue('--frozen-body-mt'), 10) * -1;
  if ($.isNumeric(pageScroll)) { // only if body is frozen already

    let revertScrollPosition = $('body').css('position') === 'fixed'; // when using freeze-only-xs body might not be "really" frozen

    // when hiding modal we go back in history which can result in reverting scrollRestoration back to auto
    // we make sure it's on manual and we will revert it to auto later
    history.scrollRestoration = 'manual';

    $('body, html').removeClass(unfreezeOnly ? unfreezeOnly : 'freeze');

    // when body is frozen and a scrollbar is present we add overflow-y-scroll to html to preserve the scroll bar
    // when we unfreeze we remove this class (even if it wasn't really added)
    $('html').removeClass('overflow-y-scroll');

    if (revertScrollPosition) $(window).scrollTop(pageScroll);
    document.documentElement.style.setProperty('--frozen-body-mt', '');

    setTimeout(function() {
      // triggering unfrozen is in setTimeout to let browser remove classes from body that freeze it
      // triggering unfrozen should come before reverting scrollRestoration to auto
      $('body').trigger('unfrozen');

      // when body is unfrozen reset scroll restoration to default (auto).
      // When unfreezing the browser can restore scroll automatically (hide modal will result in change in the url)
      // That's why we place scroll restoration in setTimeout
      history.scrollRestoration = 'auto';
    }, 0);
  }
});

// Handle pages that were loaded from cache, usually happens when clicking on the back button
$(window).bind("pageshow", function(event) {
  if (event.originalEvent.persisted) { //persisted is when page is loaded from cache
    // using reg exp to unfreeze all freeze classes like freeze-only-xs, freeze-only-md etc..
    $('body').trigger('unfreeze', function (index, className) {
      return (className.match(/(^|\s)freeze-\S+/g) || []).join(' ') + ' freeze';
    });
  }
});
