      // by clicking on it or using "Tab", when closing calendar we are focusing back to the input but calendar is still opened when focus event triggers
      // we can't use this in mobile cause focus event crate weird issues with modal so on mobile click event will open the calendar
      if (!this.calendar.isOpen && window.innerWidth >= 576) this.calendar.open();
