Initializers.bsPopover = (function($) {
  return {
    initNonLive: function(container) {
      $('[data-toggle="popover"]', container).each(function() {
        // when popover is in modal it shouldn't be contained by the body, header, footer or data-grid (by default) because of z-index issues with modal header and footer
        let overrides = {};

        if ($(this).data('container') == undefined) {
          if ($(this).closest('.popover-container').length > 0) { // popover can be contained by a parent container
            let container = $(this).closest('.popover-container')[0];
            let boundary = $(this).data('boundary') || container;
            overrides = {container: container, boundary: boundary};
          } else if ($(this).closest('.data-grid-content').length > 0) {
            overrides = {
              container: $(this).closest('.data-grid-content')[0],
              boundary: $(this).closest('.data-grid')[0]
            };
          } else if ($(this).closest('.data-grid').length > 0) {
            overrides = {
              container: $(this).closest('.data-grid')[0],
              boundary: $(this).closest('.data-grid')[0]
            };
          } else if ($(this).closest('.modal').length > 0) { // when popover is in modal it shouldn't be contained by the body (default) because of z-index issues with modal header and footer
            if ($(this).closest('.modal-body').length > 0) overrides = {
              container: $(this).closest('.modal-body')[0],
              boundary: $(this).closest('.modal-body')[0]
            };
            else if ($(this).closest('.modal-footer').length > 0) overrides = {
              container: $(this).closest('.modal-footer')[0],
              boundary: $(this).closest('.modal-content')[0]
            };
            else if ($(this).closest('.modal-header').length > 0) overrides = {
              container: $(this).closest('.modal-header')[0],
              boundary: $(this).closest('.modal-content')[0]
            };
            else overrides = {
              container: $(this).closest('.modal-content')[0],
              boundary: $(this).closest('.modal-content')[0]
            };
          }
        }

        let options = Initializers.bsPopover.getElementOptions(this, overrides);
        if ($(this).is('[data-trigger=click]')) { //when trigger is click, popover show/hide is toggled when clicking on target, we never want to hide popover when clicking target
          options.trigger = 'manual';
          $(this).removeAttr('data-trigger');
          $(this).on('click', function() {
            let api = $(this).data('bs.popover');
            if(!$(api.getTipElement()).hasClass('show')) api.show(); //show unless already visible
          });
        }
        $(this).popover(options);
      });
    },

    getElementOptions: function(element, overrides){
      element = $(element);
      var options = $.extend(
        {
          html: true,
          placement: 'auto',
          trigger: 'hover',
          dismissOnBlur: true,
        },
        element.data(),
        {
          template: $('<div class="popover popover-dismissible" role="tooltip"><div class="arrow"></div><a class="close" aria-label="Close" data-dismiss="popover"><span aria-hidden="true">&times;</span></a><h3 class="popover-header"></h3><div class="popover-body"></div></div>'),
          sanitize: false,
          title: function() {
            var html = $(this).data('title');
            if($(this).find('.popover-header').length > 0) { //take html from .popover-header wrapper inside target element
              html = $(this).find('.popover-header').html();
            }
            return html;
          },
          content: function() {
            var html = $(this).data('content');
            if($(this).find('.popover-body').length > 0){ //take html from .popover-content wrapper inside target element
              html = $(this).find('.popover-body').html();
            }
            return html;
          }
        },
        overrides || {}
      );

      if (options.trigger == 'hover') {
        options.template.removeClass('popover-dismissible');
        options.dismissOnBlur=false;
      }

      if (options.popoverClass) options.template.addClass(options.popoverClass);
      options.template = options.template[0].outerHTML

      options.animation = false;

      return options;
    }
  }
})(jQuery);
